const targetX = args.x;
const targetZ = args.z;
const targetY = args.y !== undefined ? args.y : bot.entity.position.y;
const targetPos = new Vec3(targetX, targetY, targetZ);

// 1. Prepare for combat by equipping the best available weapon
const findBestWeapon = function() {
  const items = bot.inventory.items();
  const sword = items.find(function(i) { return i.name.includes('sword'); });
  if (sword) return sword;
  const bow = items.find(function(i) { return i.name.includes('bow'); });
  if (bow) return bow;
  const axe = items.find(function(i) { return i.name.includes('_axe'); });
  return axe || null;
};

const bestWeapon = findBestWeapon();
if (bestWeapon) {
  await bot.equip(bestWeapon, 'hand');
}

// 2. Start moving to the defensive position in the background
startBackgroundSkill(bot, 'establish_defensive_position', async function(token) {
  const movements = new Movements(bot);
  bot.pathfinder.setMovements(movements);

  try {
    const goal = new goals.GoalNear(targetPos.x, targetPos.y, targetPos.z, args.radius);
    await bot.pathfinder.goto(goal);

    // 3. Once reached, stay alert and look for threats
    while (!token.cancelled && bot.entity && bot.health > 0) {
      if (!bot.physicsEnabled) {
        await new Promise(function(resolve) { setTimeout(resolve, 100); });
        continue;
      }

      const threat = bot.nearestEntity(function(entity) {
        return (entity.type === 'mob' && !['passive', 'ambient'].includes(entity.mobType)) || 
               (entity.type === 'player' && entity.username !== bot.username);
      });

      if (threat) {
        await bot.lookAt(threat.position.offset(0, threat.height, 0));
      }

      await new Promise(function(resolve) { setTimeout(resolve, 500); });
    }
  } catch (err) {
    if (!token.cancelled) {
      console.log('Defensive position movement interrupted: ' + err.message);
    }
  }
});

const weaponStatus = bestWeapon ? "equipped " + bestWeapon.name : "no weapon found";
return "<DEFENDING>: Moving to (" + targetX + ", " + targetY + ", " + targetZ + ") and " + weaponStatus + ".";
